std::string markdownToHtml(const std::string& markdown) {
    std::string html = markdown;

    // Inline replacements
    std::unordered_map<std::string, std::string> inlineReplacements = {
        {"\\*\\*(.*?)\\*\\*", "<strong>$1</strong>"}, // Bold
        {"\\*(.*?)\\*", "<em>$1</em>"},               // Italic
        {"`(.*?)`", "<code>$1</code>"},               // Inline code
        {"\\[(.*?)\\]\\((.*?)\\)", "<a href=\"$2\">$1</a>"} // Link
    };

    // Apply inline replacements
    for (const auto& [pattern, replacement] : inlineReplacements) {
        html = std::regex_replace(html, std::regex(pattern), replacement);
    }

    // Block replacements
    std::vector<std::pair<std::string, std::string>> blockReplacements = {
        {"^(#{1,6}) (.*)$", "<h$1>$2</h$1>"}, // Headings
        {"^\\* (.*)$", "<li>$1</li>"}, // Unordered list
        {"^\\d+\\. (.*)$", "<li>$1</li>"}, // Ordered list
        {"^```(.*?)\\n((.|\\n)*?)```", "<pre><code>$2</code></pre>"}, // Code block
    };

    // Apply block replacements
    for (const auto& [pattern, replacement] : blockReplacements) {
        html = std::regex_replace(html, std::regex(pattern, std::regex::multiline), replacement);
    }

    // Handle paragraphs
    std::istringstream iss(html);
    std::ostringstream oss;
    std::string line;
    bool inParagraph = false;

    while (std::getline(iss, line)) {
        if (line.empty()) {
            if (inParagraph) {
                oss << "</p>\n";
                inParagraph = false;
            }
        } else if (line.substr(0, 3) != "<h" && line.substr(0, 3) != "<li") {
            if (!inParagraph) {
                oss << "<p>";
                inParagraph = true;
            }
            oss << line << " ";
        } else {
            if (inParagraph) {
                oss << "</p>\n";
                inParagraph = false;
            }
            oss << line << "\n";
        }
    }

    if (inParagraph) {
        oss << "</p>\n";
    }

    return oss.str();
}

int main() {
    std::string markdown = R"(
# Hello, World!

This is a **bold** and *italic* text.

* Item 1
* Item 2

```cpp
#include <iostream>
int main() { return 0; }
```

[Link text](https://www.example.com)
)";

    std::string html = markdownToHtml(markdown);
    std::cout << html << std::endl;

    return 0;
}
```

