    snakeBodyTexture = IMG_LoadTexture(renderer, "snake_body.png");
    foodTexture = IMG_LoadTexture(renderer, "food.png");
    // Add error handling for texture loading
}

void close() {
    SDL_DestroyTexture(snakeHeadTexture);
    SDL_DestroyTexture(snakeBodyTexture);
