function checkPrimes(numbers) {
    // Check if the input array has exactly 5 numbers
    if (!Array.isArray(numbers) || numbers.length !== 5) {
        console.error("Error: Input must be an array containing exactly 5 numbers.");
        return;
    }

    // Helper function to check if a number is prime
    function isPrime(num) {
        if (typeof num !== 'number' || num <= 1) return false; // Non-numeric or <= 1 are not prime
        if (num <= 3) return true; // 2 and 3 are prime numbers

        if (num % 2 === 0 || num % 3 === 0) return false;

        for (let i = 5; i * i <= num; i += 6) {
            if (num % i === 0 || num % (i + 2) === 0) return false;
        }

        return true;
    }

    // Check each number in the array
    for (let number of numbers) {
        if (isPrime(number)) {
            console.log(`${number} is a prime number.`);
        }
    }
}

// Example usage:
